class Solution(object):
    def minimumCost(self, s):
        n = len(s)
        total = 0
        # At each boundary between s[i] and s[i+1]:
        # if they differ, we must make a cut here.
        # Cost of fixing left side (prefix [0..i]): i+1
        # Cost of fixing right side (suffix [i+1..n-1]): n-i-1
        # Take minimum.
        for i in range(n - 1):
            if s[i] != s[i + 1]:
                total += min(i + 1, n - i - 1)
        return total
